pages/account/add-payment-method:
{{#partial "page"}}

    {{inject 'creditCardNumber' (lang 'forms.validate.payment_method.credit_card_number')}}
    {{inject 'expiration' (lang 'forms.validate.payment_method.expiration')}}
    {{inject 'nameOnCard' (lang 'forms.validate.payment_method.name_on_card')}}
    {{inject 'cvv' (lang 'forms.validate.payment_method.cvv')}}

    {{inject 'firstNameLabel' (lang 'forms.payment_methods.first_name')}}
    {{inject 'lastNameLabel' (lang 'forms.payment_methods.last_name')}}
    {{inject 'companyLabel' (lang 'forms.payment_methods.company')}}
    {{inject 'phoneLabel' (lang 'forms.payment_methods.phone')}}
    {{inject 'address1Label' (lang 'forms.payment_methods.address1')}}
    {{inject 'address2Label' (lang 'forms.payment_methods.address2')}}
    {{inject 'cityLabel' (lang 'forms.payment_methods.city')}}
    {{inject 'countryLabel' (lang 'forms.payment_methods.country')}}
    {{inject 'stateLabel' (lang 'forms.payment_methods.state')}}
    {{inject 'postalCodeLabel' (lang 'forms.payment_methods.postal_code')}}
    {{inject 'chooseCountryLabel' (lang 'forms.payment_methods.choose_country')}}

    {{inject 'paymentMethodsUrl' urls.account.payment_methods.all}}
    {{inject 'paymentsUrl' settings.payments_url}}
    {{inject 'storeHash' settings.store_hash}}
    {{inject 'vaultToken' vault.access_token}}
    {{inject 'shopperId' customer.id}}
    {{inject 'countries' countries}}
    {{inject 'customerEmail' customer.email}}
    {{inject 'providerId' forms.provider}}
    {{inject 'currencyCode' currency_selector.active_currency_code}}
    {{inject 'paymentProviderInitializationData' initialization_data}}
    {{inject 'storeLocale' settings.request.locale }}
    {{inject 'themeSettings' theme_settings}}

    {{> components/common/breadcrumbs breadcrumbs=breadcrumbs}}

    <h2 class="page-heading">{{lang 'forms.payment_methods.add.heading'}}</h2>

    {{> components/account/navigation account_page='payment_methods'}}

    <div class="account account--fixed">

        {{#if forms.error}}
            {{> components/common/alert/alert-error forms.error}}
        {{/if}}

        {{#if account_payments}}
            {{{ account_payments }}}
            <script nonce="{{nonce}}">
                window.BigCommerce = window.BigCommerce || {};
            </script>
        {{else}}
            <form data-payment-method-form class="form">
                <input type="hidden" name="email" value="{{customer.email}}">
                <input type="hidden" name="provider_id" value="{{forms.provider}}">
                <input type="hidden" name="currency_code" value="{{currency_selector.active_currency_code}}">

                <h3 class="paymentMethodForm-heading">{{lang 'account.payment_methods.payment_method'}}</h3>
                <div class="paymentMethodForm">
                    <p class="paymentMethodForm-subheading">
                        {{forms.payment_method.provider_name}}
                        <span class="paymentMethodForm-cards">
                            {{#each ../theme_settings.supported_card_type_icons}}
                                <img class="paymentMethodForm-cards-icon" src="{{cdn (concat (concat 'img/payment-methods/' this) '.svg')}}" alt="{{lang (concat 'account.payment_methods.card_types.' this)}}" title="{{lang (concat 'account.payment_methods.card_types.' this)}}">
                            {{/each}}
                        </span>
                    </p>
                    <fieldset class="form-fieldset">
                        <div class="paymentMethodForm-column">
                            <div class="paymentMethodForm-inputs">
                                {{> components/common/forms/text id="credit_card_number" name="credit_card_number" label=(lang 'account.payment_methods.credit_card_number')}}
                                <svg class="paymentMethodForm-inputs-icon icon">
                                    <use href="#icon-lock" />
                                </svg>
                            </div>
                            <div class="paymentMethodForm-inputs">
                                {{> components/common/forms/text id="expiration" name="expiration" label=(lang 'account.payment_methods.expiration') placeholder="MM/YY"}}
                            </div>
                        </div>
                        <div class="paymentMethodForm-column">
                            <div class="paymentMethodForm-inputs">
                                {{> components/common/forms/text id="name_on_card" name="name_on_card" label=(lang 'account.payment_methods.name_on_card')}}
                            </div>
                            <div class="paymentMethodForm-inputs">
                                {{> components/common/forms/text id="cvv" name="cvv" label=(lang 'account.payment_methods.cvv')}}
                                <svg class="paymentMethodForm-inputs-icon icon">
                                    <use href="#icon-lock" />
                                </svg>
                            </div>
                        </div>
                        <div class="form-field">
                            <input type="checkbox" name="default_instrument" id="default_instrument" data-label="{{lang 'forms.payment_methods.default_instrument'}}" class="form-checkbox">
                            <label class="form-label" for="default_instrument">{{lang 'forms.payment_methods.default_instrument'}}</label>
                        </div>
                    </fieldset>
                </div>

                <h3 class="paymentMethodForm-heading">{{lang 'account.payment_methods.billing_address'}}</h3>

                <fieldset class="form-fieldset">
                    <div class="form-row form-row--half">
                        {{> components/common/forms/text private_id="FirstName" required=true id="first_name" name="first_name" label=(lang 'forms.payment_methods.first_name')}}
                        {{> components/common/forms/text private_id="LastName" required=true id="last_name" name="last_name" label=(lang 'forms.payment_methods.last_name')}}
                        {{> components/common/forms/text private_id="CompanyName" required=false id="company" name="company" label=(lang 'forms.payment_methods.company')}}
                        {{> components/common/forms/text private_id="Phone" required=false id="phone" name="phone" label=(lang 'forms.payment_methods.phone')}}
                        {{> components/common/forms/text private_id="AddressLine1" required=true id="address1" name="address1" label=(lang 'forms.payment_methods.address1')}}
                        {{> components/common/forms/text private_id="AddressLine2" required=false id="address2" name="address2" label=(lang 'forms.payment_methods.address2')}}
                        {{> components/common/forms/text private_id="City" required=true id="city" name="city" label=(lang 'forms.payment_methods.city')}}
                        {{> components/common/forms/select private_id="Country" required=true id="country" name="country" label=(lang 'forms.payment_methods.country') chooseprefix=(lang 'forms.payment_methods.choose_country') options=countries}}
                        {{> components/common/forms/text private_id="State" required=true id="state" name="state" label=(lang 'forms.payment_methods.state')}}
                        {{> components/common/forms/text private_id="Zip" required=true id="postal_code" name="postal_code" label=(lang 'forms.payment_methods.postal_code')}}
                    </div>
                </fieldset>
                <div class="form-actions">
                    <input type="submit" class="button button--primary" value="{{lang 'forms.payment_methods.submit_value'}}">
                    <a href="{{urls.account.payment_methods.all}}" class="button">{{lang 'common.cancel'}}</a>
                    {{inject 'required' (lang 'common.required')}}
                    {{inject 'state_error' (lang 'errors.state_error')}}
                    {{inject 'generic_error' (lang 'common.generic_error')}}
                </div>
            </form>
        {{/if}}
    </div>

{{/partial}}
{{> layout/base}}

components/common/footer:
{{#if banners.bottom}}
    <div class="banners" data-banner-location="bottom">
        {{#each (limit banners.bottom_metadata 1)}}
            <div class="banner" data-event-type="promotion" data-entity-id="{{this.id}}" data-name="{{this.banner-name}}" data-position="{{this.location}}" data-name="{{this.banner-name}}">
                <div data-event-type="promotion-click">
                    {{{this.content}}}
                </div>
            </div>
        {{/each}}
    </div>
{{/if}}
<div class="container">{{{region name="page_bottom"}}}</div>
<div class="container">{{{region name="newsletter_above--global"}}}</div>
{{#all settings.show_newsletter_box theme_settings.epic-toggle-newsletter (if theme_settings.epic-newsletter-location '===' 'inline')}}
    <div class="newsletter">
        <div class="container">
            {{#if theme_settings.epic-toggle-newsletter}}
                {{#if theme_settings.epic-toggle-newsletter-widgets}}
                    {{{region name="newsletter--global"}}}
                {{else if settings.show_newsletter_box}}
                    <div class="newsletter-box">
                        {{> components/common/subscription-form}}
                    </div>
                {{/if}}
            {{else if settings.show_newsletter_box}}
                <div class="newsletter-box">
                    {{> components/common/subscription-form}}
                </div>
            {{/if}}
        </div>
    </div>
{{/all}}
<div class="container">{{{region name="footer_above--global"}}}</div>
<footer class="footer" role="contentinfo">
    <h2 class="footer-title-sr-only">{{lang 'footer.title'}}</h2>
    <div class="container">
        <section class="footer-info footer-info-cols--{{theme_settings.epic-footer-number-of-columns}}">
            {{#gte theme_settings.epic-footer-number-of-columns 1}}
                <article class="footer-info-col footer-info-col--small">
                    <h3 class="footer-info-heading">{{theme_settings.epic-footer-heading-column-one}}</h3>
                    {{#unless theme_settings.epic-toggle-footer-widgets}}
                        {{#if theme_settings.epic-show-footer-tagline}}
                            <p>{{theme_settings.epic-footer-tagline}}</p>
                        {{/if}}
                        {{#if settings.address}}
                            <address>{{nl2br settings.address}}</address>
                        {{/if}}
                        {{#if settings.phone_number}}
                            <a href="tel:{{settings.phone_number}}">{{settings.phone_number}}</a>
                        {{/if}}
                    {{/unless}}
                    {{{region name="footer_column_one--global"}}}
                    {{#if theme_settings.social_icon_placement_top}}
                      {{#and (if theme_settings.social_icon_placement_bottom '!==' 'bottom_none') (if theme_settings.social_icon_placement_bottom '==' 'bottom_left')}}
                          {{> components/common/social-links}}
                      {{/and}}
                    {{/if}}
                </article>
            {{/gte}}

            {{#gte theme_settings.epic-footer-number-of-columns 2}}
                <article class="footer-info-col footer-info-col--small">
                    <h3 class="footer-info-heading">{{theme_settings.epic-footer-heading-column-two}}</h3>
                    {{#unless theme_settings.epic-toggle-footer-widgets}}
                        <ul class="footer-info-list">
                            {{#each categories}}
                                <li>
                                    <a href="{{url}}">{{name}}</a>
                                </li>
                            {{/each}}
                        </ul>
                    {{/unless}}
                    {{{region name="footer_column_two--global"}}}
                </article>
            {{/gte}}

            {{#gte theme_settings.epic-footer-number-of-columns 3}}
                <article class="footer-info-col footer-info-col--small">
                    <h3 class="footer-info-heading">{{theme_settings.epic-footer-heading-column-three}}</h3>
                    {{#unless theme_settings.epic-toggle-footer-widgets}}
                        <ul class="footer-info-list">
                            {{#and theme_settings.shop_by_brand_show_footer shop_by_brand.length}}
                                {{#each shop_by_brand}}
                                    <li>
                                        <a href="{{url}}">{{name}}</a>
                                    </li>
                                {{/each}}
                                <li><a href="{{urls.brands}}">{{lang 'common.view_all'}}</a></li>
                            {{else}}
                                {{#each pages}}
                                    <li>
                                        <a href="{{url}}">{{name}}</a>
                                    </li>
                                {{/each}}
                                <li>
                                    <a href="{{urls.sitemap}}">{{lang 'sitemap.page_title'}}</a>
                                </li>
                            {{/and}}
                        </ul>
                    {{/unless}}
                    {{{region name="footer_column_three--global"}}}
                </article>
            {{/gte}}

            {{#gte theme_settings.epic-footer-number-of-columns 4}}
                <article class="footer-info-col footer-info-col--small">
                    <h3 class="footer-info-heading">{{theme_settings.epic-footer-heading-column-four}}</h3>
                    {{#unless theme_settings.epic-toggle-footer-widgets}}
                        <ul class="footer-info-list">
                            {{#each pages}}
                                <li>
                                    <a href="{{url}}">{{name}}</a>
                                </li>
                            {{/each}}
                            <li>
                                <a href="{{urls.sitemap}}">{{lang 'sitemap.page_title'}}</a>
                            </li>
                        </ul>
                    {{/unless}}
                    {{{region name="footer_column_four--global"}}}
                </article>
            {{/gte}}

            {{#gte theme_settings.epic-footer-number-of-columns 5}}
                <article class="footer-info-col footer-info-col--small">
                    <h3 class="footer-info-heading">{{theme_settings.epic-footer-heading-column-five}}</h3>
                    {{#all settings.show_newsletter_box theme_settings.epic-toggle-newsletter (if theme_settings.epic-newsletter-location '===' 'column')}}
                        {{#if theme_settings.epic-toggle-newsletter}}
                            {{#if theme_settings.epic-toggle-newsletter-widgets}}
                                {{{region name="newsletter--column"}}}
                            {{else if settings.show_newsletter_box}}
                                <div class="newsletter-column">
                                    {{> components/common/subscription-form location='column'}}
                                </div>
                            {{/if}}
                        {{else if settings.show_newsletter_box}}
                            <div class="newsletter-column">
                                {{> components/common/subscription-form}}
                            </div>
                        {{/if}}
                    {{else}}
                        {{#unless theme_settings.epic-toggle-footer-widgets}}
                            <ul class="footer-info-list">
                                {{#each pages}}
                                    <li>
                                        <a href="{{url}}">{{name}}</a>
                                    </li>
                                {{/each}}
                                <li>
                                    <a href="{{urls.sitemap}}">{{lang 'sitemap.page_title'}}</a>
                                </li>
                            </ul>
                        {{/unless}}
                        {{{region name="footer_column_five--global"}}}
                    {{/all}}
                </article>
            {{/gte}}
        </section>
    </div>
    <div class="container">{{{region name="footer_below--global"}}}</div>
    {{{region name="ssl_site_seal--global"}}}
  {{#and theme_settings.show_powered_by theme_settings.show_copyright_footer}}
      <div class="footer-bottom">
          <div class="container">
              <div class="footer-copyright footer-copyright__split">
                  <p class="powered-by">{{lang 'footer.powered_by'}} <a href="https://www.bigcommerce.com?utm_source=merchant&amp;utm_medium=poweredbyBC" rel="nofollow" target="_blank">BigCommerce</a> and <a href="https://www.epicdesignlabs.com" target="_blank">Epic Design Labs</a></p>
                  <div class="footer-copyright__split-copy">
                    {{> components/common/payment-icons}}
                    <p class="powered-by">&copy; {{moment format="YYYY"}} {{settings.store_name}} {{lang 'footer.rights_reserved'}}</p>
                  </div>
              </div>
          </div>
      </div>
  {{else}}
      {{#if theme_settings.show_powered_by}}
          <div class="footer-bottom">
              <div class="container">
                  <div class="footer-copyright">
                      <p class="powered-by">{{lang 'footer.powered_by'}} <a href="https://www.bigcommerce.com?utm_source=merchant&amp;utm_medium=poweredbyBC" rel="nofollow" target="_blank">BigCommerce</a> and <a href="https://www.epicdesignlabs.com" target="_blank">Epic Design Labs</a></p>
                  </div>
              </div>
          </div>
      {{/if}}
      {{#if theme_settings.show_copyright_footer}}
          <div class="footer-bottom">
              <div class="container">
                  <div class="footer-copyright footer-copyright--{{theme_settings.epic-align-copyright}}{{#if theme_settings.epic-toggle-copyright-border-top}} footer-copyright--has-bdr{{/if}}">
                      <p class="powered-by">&copy; {{moment format="YYYY"}} {{settings.store_name}} {{lang 'footer.rights_reserved'}}</p>
                      {{#if theme_settings.epic-toggle-copyright-links}}
                          {{assignVar 'show_links' 'false'}}
                          {{#all (if theme_settings.epic-copyright-link-one-label '!=='  '') (if theme_settings.epic-copyright-link-one-url '!==' '') (if (getVar 'show_links') '!==' 'true')}}
                              {{assignVar 'show_links' 'true'}}
                          {{/all}}
                          {{#all (if theme_settings.epic-copyright-link-two-label '!=='  '') (if theme_settings.epic-copyright-link-two-url '!==' '') (if (getVar 'show_links') '!==' 'true')}}
                              {{assignVar 'show_links' 'true'}}
                          {{/all}}
                          {{#all (if theme_settings.epic-copyright-link-three-label '!=='  '') (if theme_settings.epic-copyright-link-three-url '!==' '') (if (getVar 'show_links') '!==' 'true')}}
                              {{assignVar 'show_links' 'true'}}
                          {{/all}}
                          {{#if (getVar 'show_links') '==' 'true'}}
                              <ul class="footer-copyright-links">
                                  {{#and (if theme_settings.epic-copyright-link-one-label '!=='  '') (if theme_settings.epic-copyright-link-one-url '!==' '')}}
                                      <li class="footer-copyright-item">
                                          <a href="{{theme_settings.epic-copyright-link-one-url}}">{{{theme_settings.epic-copyright-link-one-label}}}</a>
                                      </li>
                                  {{/and}}
                                  {{#and (if theme_settings.epic-copyright-link-two-label '!=='  '') (if theme_settings.epic-copyright-link-two-url '!==' '')}}
                                      <li class="footer-copyright-item">
                                          <a href="{{theme_settings.epic-copyright-link-two-url}}">{{{theme_settings.epic-copyright-link-two-label}}}</a>
                                      </li>
                                  {{/and}}
                                  {{#and (if theme_settings.epic-copyright-link-three-label '!=='  '') (if theme_settings.epic-copyright-link-three-url '!==' '')}}
                                      <li class="footer-copyright-item">
                                          <a href="{{theme_settings.epic-copyright-link-three-url}}">{{{theme_settings.epic-copyright-link-three-label}}}</a>
                                      </li>
                                  {{/and}}
                              </ul>
                          {{/if}}
                      {{/if}}
                      {{#if theme_settings.social_icon_placement_top}}
                        {{#and (if theme_settings.social_icon_placement_bottom '!==' 'bottom_none') (if theme_settings.social_icon_placement_bottom '==' 'bottom_right')}}
                            {{> components/common/social-links}}
                        {{/and}}
                      {{/if}}
                      {{> components/common/payment-icons}}
                  </div>
              </div>
          </div>
      {{/if}}
  {{/and}}
</footer>

components/common/channel-selector:
{{#if theme_settings.channels.length '>' 1}}
<ul class="navUser-section">
    <li class="navUser-item">
        <a href="#"
           class="navUser-action navUser-action--channelSelector has-dropdown"
           data-dropdown="channelSelection"
           aria-controls="channelSelection"
           aria-expanded="false"
        >
            {{#each theme_settings.channels}}
                {{#if is_active}}
                    {{lang 'common.channel' code=code}}
                {{/if}}
            {{/each}}
            <i class="icon" aria-hidden="true">
                <svg>
                    <use href="#icon-chevron-down"/>
                </svg>
            </i>
        </a>
        <ul class="dropdown-menu" id="channelSelection" data-dropdown-content aria-hidden="true" tabindex="-1">
            {{#each theme_settings.channels}}
                <li class="dropdown-menu-item">
                    <a href="{{{switch_url}}}" data-channel-code="{{{code}}}" data-warning="{{lang 'common.channel_switch_warning'}}">
                        {{#if is_active}}
                            <strong>{{name}}</strong>
                        {{else}}
                            {{name}}
                        {{/if}}
                    </a>
                </li>
            {{/each}}
        </ul>
    </li>
</ul>
{{/if}}

components/common/navigation-list-altern:
